INSERT INTO `workstatus` (`ws_id`, `ws_name`, `info`, `list`, `public`, `modified`, `user_id`) VALUES
(1, 'N01. รับงาน', 'บันทึกข้อมูลงานที่รับเข้าบริษัท', 1, 1, '2019-04-24 15:01:39', 2),
(2, 'N02. ออกแบบตรวจเช็ค', 'หัวหน้าช่างเลือกผู้รับผิดชอบงานนั้น(เลือกช่าง) และช่างที่ได้รับมอบหมายดำเนินการตรวจเช็ค, ออกแบบ, ผลิต', 2, 1, '2019-04-24 15:28:29', 2),
(3, 'N03. ขอข้อมูลเพิ่มเติมฝ่ายขาย', 'ทางช่างขอข้อมูลเพิ่มเติมจาก SALE ในงานที่อาจจะติดปัญหา', 3, 1, '2019-04-24 15:28:52', 2),
(4, 'N04. หาราคาอะไหล่', 'ทางช่างขออะไหล่ กรอกข้อมูลครบถ้วน (หาราคาอะไหล่)\r\nพร้อมให้ฝ่ายขายเสนอราคาให้ลูกค้า', 4, 1, '2019-04-24 15:29:16', 2),
(5, 'N05. หาราคาเสร็จสิ้น', 'หาราคาอะไหล่ครบถ้วนทุกรายการเรียบร้อย', 5, 1, '2019-04-24 15:29:42', 2),
(6, 'N06. เสนอราคา', 'จัดทำเอกสารใบเสนอราคาให้ทางลูกค้าแล้ว', 6, 1, '2019-05-14 10:18:05', 0),
(7, 'N07. รอ PO ลูกค้า', 'เสนอราคาแล้ว รอลูกค้าพิจารณาว่าต้องการซ่อมหรือไม่', 7, 1, '2019-05-14 10:18:56', 0),
(8, 'N08. PO มาแล้ว', 'ลูกค้าอนุมัติซ่อมแล้ว', 8, 1, '2019-05-14 10:21:21', 0),
(9, 'N09. เปิด PR ', 'ขออนุมัติซื้ออะไหล่ ( เอกสาร )', 9, 1, '2019-05-14 10:22:49', 0),
(10, 'N10. เปิด PO จัดซื้อ', 'ได้รับการอนุมัติ PR แล้ว เปิด PO สั่งซื้อสินค้า', 10, 1, '2019-05-14 10:24:15', 0),
(11, 'N11. รอบัญชีชำระเงิน', 'ใส่เลข PO I-money เรียบร้อยแล้ว (รอทางบัญชีทำขั้นตอนการจ่ายเงิน เงินสด, เช็ค, โอน, เครดิต)', 11, 1, '2019-05-14 13:30:26', 0),
(12, 'N12. รอรับของ(อะไหล่)', 'บัญชีชำระเงินเรียบร้อยแล้ว สั่งของกับ Supplier เรียบร้อย', 12, 1, '2019-05-14 13:41:57', 0),
(13, 'N13. ของมาแล้ว ', 'สินค้าที่สั่งกับ Supplier ดำเนินการส่งของแล้ว (Stroe ทำใบรับสินค้า)\r\nนำสินค้าเข้าสโตร์เพื่อช่างมาเบิกใช้งาน', 13, 1, '2019-05-14 13:45:12', 0),
(14, 'N14. ดำเนินการผลิต(อะไหล่มาครบ)', 'ช่างได้รับอะไหล่เรียบร้อยแล้ว\r\n', 14, 1, '2019-05-14 14:04:59', 0),
(15, 'N15. ซ่อมเสร็จแล้ว', 'ช่างดำเนินการซ่อม ผลิต เรียบร้อย', 15, 1, '2019-05-14 14:05:49', 0),
(16, 'N16. ส่งของเทส', 'ช่างซ่อมเสร็จ Sale นำงานไปเทสให้ลูกค้า (ต้องมีเอกสารใบส่งของอ้างอิง)', 16, 1, '2019-05-14 16:28:20', 0),
(17, 'N17. รอเก็บเงิน', 'ใส่เลขที่เอกสารวางบิลและเลขที่เอกสารใบกำกับภาษี', 17, 1, '2019-05-15 09:40:56', 1098),
(18, 'N18. ปิดงาน', 'ใส่เลขที่เอกสารใบเสร็จรับเงิน (จบงาน)', 18, 1, '2019-05-15 09:41:54', 1098),
(19, 'N19. ยกเลิก-คืนงาน', 'ลูกค้าไม่ซ่อมหรือถึงกำหนดคืนงาน (ต้องมีเลขที่เอกสารใบส่งของคืนอ้างอิง)', 19, 1, '2019-05-15 09:42:48', 1098),
(20, 'เครม', 'ไม่ผ่าน', 20, 1, '2019-09-04 15:01:05', 0);
